<?php
require_once __DIR__ . '/bootstrap.php'; require_auth(); $pdo=db();
if(method()==='GET'){ $tripId=int_param('trip_id'); if(!$tripId)json_response(['error'=>'Missing trip_id'],400); $s=$pdo->prepare('SELECT * FROM events WHERE trip_id=? ORDER BY start_date ASC,start_time ASC,sort_order ASC,id ASC');$s->execute([$tripId]);$rows=$s->fetchAll();foreach($rows as &$r){$decoded=$r['data_json']?json_decode($r['data_json'],true):[];$normalized=normalize_event_type_and_data($r['event_type']??'',is_array($decoded)?$decoded:[]);$r['event_type']=$normalized['event_type'];$r['data']=$normalized['data'];$r['display_mode']=normalize_display_mode_value($r['display_mode']??null,$r['event_type']);unset($r['data_json']);}json_response($rows); }
if(method()==='POST'){ $d=input_json(); $tripId=(int)($d['trip_id']??0); if(!$tripId)json_response(['error'=>'Missing trip_id'],400); $normalized=normalize_event_type_and_data(clean_string($d['event_type']??null,50)?:'poi',$d['data']??[]); $displayMode=normalize_display_mode_value(clean_string($d['display_mode']??null,20),$normalized['event_type']); $s=$pdo->prepare('INSERT INTO events (trip_id,event_type,title,start_date,start_time,end_date,end_time,notes,data_json,sort_order,display_mode) VALUES (?,?,?,?,?,?,?,?,?,?,?)'); $s->execute([$tripId,$normalized['event_type'],clean_string($d['title']??null,255)?:'Ny event',clean_string($d['start_date']??null,20)?:date('Y-m-d'),clean_string($d['start_time']??null,20),clean_string($d['end_date']??null,20),clean_string($d['end_time']??null,20),clean_string($d['notes']??null,5000),json_encode($normalized['data'],JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES),(int)($d['sort_order']??0),$displayMode]); json_response(['id'=>(int)$pdo->lastInsertId()],201); }
if(method()==='PUT'){ $d=input_json(); $id=(int)($d['id']??0); if(!$id)json_response(['error'=>'Missing id'],400); $normalized=normalize_event_type_and_data(clean_string($d['event_type']??null,50)?:'poi',$d['data']??[]); $displayMode=normalize_display_mode_value(clean_string($d['display_mode']??null,20),$normalized['event_type']); $s=$pdo->prepare('UPDATE events SET event_type=?,title=?,start_date=?,start_time=?,end_date=?,end_time=?,notes=?,data_json=?,sort_order=?,display_mode=? WHERE id=?'); $s->execute([$normalized['event_type'],clean_string($d['title']??null,255)?:'Event',clean_string($d['start_date']??null,20)?:date('Y-m-d'),clean_string($d['start_time']??null,20),clean_string($d['end_date']??null,20),clean_string($d['end_time']??null,20),clean_string($d['notes']??null,5000),json_encode($normalized['data'],JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES),(int)($d['sort_order']??0),$displayMode,$id]); json_response(['ok'=>true]); }
if(method()==='DELETE'){ $id=int_param('id'); if(!$id)json_response(['error'=>'Missing id'],400);$s=$pdo->prepare('DELETE FROM events WHERE id=?');$s->execute([$id]);json_response(['ok'=>true]); }
json_response(['error'=>'Method not allowed'],405);
